# What is the unlocking script in this transaction
# transaction=""
#!/bin/bash
# Raw transaction hex to inspect
raw_tx_hex=""

# Decoding the raw transaction and extracting the unlocking script (scriptSig)
# from the first input (vin[0])
# The unlocking script provides the data (e.g., signature + public key)
# needed to satisfy the conditions set by the previous transaction’s locking script
unlocking_script_hex=$(bitcoin-cli -regtest -named decoderawtransaction hexstring=$raw_tx_hex \
  | jq -r '.vin[0].scriptSig.hex')

# Output the unlocking script in hex format
echo $unlocking_script_hex